func PerfQueryInstance(ProviderHandle foundation.HANDLE, CounterSetGuid *win32.GUID, Name string, Id uint32) (*systemperformance.PERF_COUNTERSET_INSTANCE, error) {
	_Name := win32.UTF16Ptr(Name)
	return systemperformance.PerfQueryInstance(ProviderHandle, CounterSetGuid, foundation.PWSTR(_Name), Id)
}

